/index.ts, server/middleware/auth.ts. Avoid known landmine: server/routes/health.ts is a high-blast-radius area (9) with elevated complexity.. Risk is medium; keep edits narrow.\",\"inspections\":{\"reads\":[{\"path\":\"server/routes/health.ts\",\"content\":\"/**\\n * Health route — System readiness check.\\n *\\n * GET /health — Reports system status:\\n *   - Server uptime\\n *   - Crucibulum connection status\\n *   - Worker availability per role\\n *   - Port status\\n *   - WebSocket client count\\n */\\n\\nimport type { FastifyPluginAsync, FastifyRequest, FastifyReply } from \\\"fastify\\\";\\nimport type { ServerContext } from \\\"../index.js\\\";\\nimport type { WorkerType } from \\\"../../workers/base.js\\\";\\n\\n// ─── Routes ──────────────────────────────────────────────────────────\\n\\nexport const healthRoutes: FastifyPluginAsync = async (fastify) => {\\n  const ctx = (): ServerContext => fastify.ctx;\\n\\n  const WORKER_TYPES: WorkerType[] = [\\\"scout\\\", \\\"builder\\\", \\\"critic\\\", \\\"verifier\\\", \\\"integrator\\\"];\\n\\n  /**\\n   * GET /health — Full system health check.\\n   */\\n  fastify.get(\\n    \\\"/health\\\",\\n    async (_request: FastifyRequest, reply: FastifyReply) => {\\n      const context = ctx();\\n\\n      // Worker availability\\n      const workerStatus: Record<string, { available: boolean; count: number }> = {};\\n      let allWorkersAvailable = true;\\n\\n      for (const type of WORKER_TYPES) {\\n        const workers = context.workerRegistry.getWorkers(type);\\n        workerStatus[type] = {\\n          available: workers.length > 0,\\n          count: workers.length,\\n        };\\n        if (workers.length === 0) allWorkersAvailable = false;\\n      }\\n\\n      // Uptime\\n      const startedAt = new Date(context.startedAt);\\n      const uptimeMs = Date.now() - startedAt.getTime();\\n\\n      // WebSocket clients\\n      const wsClients = context.eventBus.clientCount();\\n\\n      // Overall status\\n      const status = allWorkersAvailable ? \\\"healthy\\\" : \\\"degraded\\\";\\n\\n      reply.send({\\n        status,\\n        timestamp: new Date().toISOString(),\\n        uptime_ms: uptimeMs,\\n        uptime_human: formatUptime(uptimeMs),\\n        port: context.config.port,\\n        workers: workerStatus,\\n        all_workers_available: allWorkersAvailable,\\n        websocket: {\\n          connected_clients: wsClients,\\n          endpoint: `/ws`,\\n        },\\n        crucibulum: {\\n          connected: false, // TODO: wire up when Crucibulum is integrated\\n          last_sync: null,\\n        },\\n        version: \\\"0.1.0\\\",\\n      });\\n    }\\n  );\\n\\n  /**\\n   * GET /ready — Lightweight readiness probe for load balancers.\\n   */\\n  fastify.get(\\n    \\\"/ready\\\",\\n    async (_request: FastifyRequest, reply: FastifyReply) => {\\n      reply.send({ ready: true });\\n    }\\n  );\\n};\\n\\n// ─── Helpers ─────────────────────────────────────────────────────────\\n\\nfunction formatUptime(ms: number): string {\\n  const seconds = Math.floor(ms / 1000);\\n  const minutes = Math.floor(seconds / 60);\\n  const hours = Math.floor(minutes / 60);\\n  const days = Math.floor(hours / 24);\\n\\n  if (days > 0) return `${days}d ${hours % 24}h ${minutes % 60}m`;\\n  if (hours > 0) return `${hours}h ${minutes % 60}m ${seconds % 60}s`;\\n  if (minutes > 0) return `${minutes}m ${seconds % 60}s`;\\n  return `${seconds}s`;\\n}\\n\",\"lineCount\":99},{\"path\":\"server/routes/tasks.ts\",\"content\":\"/**\\n * Task routes — Submit, query, and cancel build tasks.\\n *\\n * POST /tasks       — Submit a new task, returns { task_id, run_id }\\n * GET  /tasks/:id   — Status + current run state\\n * GET  /tasks/:id/receipts — Full receipt bundle\\n * POST /tasks/:id/cancel — Cancel a running task\\n * DELETE /tasks/:id — Cancel a running task\\n */\\n\\nimport { randomUUID } from \\\"crypto\\\";\\nimport { existsSync } from \\\"fs\\\";\\nimport type { FastifyPluginAsync, FastifyRequest, FastifyReply } from \\\"fastify\\\";\\nimport { askLoqui } from \\\"../../core/loqui.js\\\";\\nimport { routeLoquiInput, type LoquiRouteDecision } from \\\"../../core/loqui-router.js\\\";\\nimport type { LoquiIntentContext } from \\\"../../core/loqui-intent.js\\\";\\nimport { generateDryRun } from \\\"../../core/dry-run.js\\\";\\nimport type { ServerContext } from \\\"../index.js\\\";\\n\\n// ─── Request/Response Schemas ────────────────────────────────────────\\n\\ninterface SubmitBody {\\n  /** Natural language prompt — also accepted as \\\"input\\\" */\\n  prompt?: string;\\n  input?: string;\\n  /** Repo path to operate on */\\n  repoPath?: string;\\n  exclusions?: string[];\\n  quality_bar?: \\\"minimal\\\" | \\\"standard\\\" | \\\"hardened\\\";\\n}\\n\\ninterface TaskParams {\\n  id: string;\\n}\\n\\ninterface LoquiBody {\\n  question: string;\\n  repoPath: string;\\n}\\n\\n/**\\n * Unified Loqui route request body. A single freeform input stream\\n * that the classifier will route to build / answer / resume /\\n * clarify. The `context` field is optional — the UI passes it when\\n * it knows about a prior run so the classifier can emit resume_run\\n * or status intents safely (see core/loqui-intent.ts Rule B).\\n */\\ninterface LoquiUnifiedBody {\\n  input: string;\\n  repoPath: string;\\n  context?: LoquiIntentContext;\\n}\\n\\n// ─── In-memory run tracker (bridges POST → Coordinator → WS) ────────\\n\\ninterface TrackedRun {\\n  taskId: string;\\n  runId: string;\\n  status: \\\"queued\\\" | \\\"running\\\" | \\\"complete\\\" | \\\"partial\\\" | \\\"failed\\\" | \\\"cancelled\\\";\\n  prompt: string;\\n  submittedAt: string;\\n  completedAt: string | null;\\n  receipt: unknown | null;\\n  error: string | null;\\n}\\n\\nconst trackedRuns = new Map<string, TrackedRun>();\\n\\nexport function getTrackedRun(taskId: string): TrackedRun | undefined {\\n  return trackedRuns.get(taskId);\\n}\\n\\n/**\\n * Snapshot of every tracked run, newest first. Read-only — returns\\n * a fresh array so callers can iterate / sort / slice without\\n * touching the internal Map. Used by the external API layer\\n * (Metrics + External API v1) so /metrics, /runs, and /runs/:id\\n * can aggregate across the same registry that /tasks writes to,\\n * without importing the private Map or creating a second source\\n * of truth.\\n */\\nexport function getAllTrackedRuns(): readonly TrackedRun[] {\\n  const out = [...trackedRuns.values()];\\n  out.sort((a, b) => (a.submittedAt < b.submittedAt ? 1 : -1));\\n  return out;\\n}\\n\\n/** Exported type for the external API routes. */\\nexport type { TrackedRun };\\n\\n/**\\n * Result from submitBuildTask — may be a running build, a clarification\\n * request, or a decomposition plan.\\n */\\ntype BuildSubmitResult =\\n  | { kind: \\\"running\\\"; taskId: string; runId: string; prompt: string; repoPath: string | null }\\n  | { kind: \\\"needs_clarification\\\"; question: string }\\n  | { kind: \\\"needs_decomposition\\\"; taskId: string; plan: unknown; message: string };\\n\\n/**\\n * Shared build-submit helper. Dispatches a build task through the\\n * Coordinator (via submitWithGates) and registers the tracked run state.\\n * Used by both the legacy POST /tasks handler and the new unified POST\\n * /tasks/loqui path so we get exactly one code path for \\\"start a build.\\\"\\n *\\n * Now returns a discriminated union so callers can handle clarification\\n * and decomposition gates without starting execution.\\n */\\nasync function submitBuildTask(\\n  ctx: ServerContext,\\n  prompt: string,\\n  repoPath: string | undefined,\\n  exclusions: string[] | undefined,\\n): Promise<BuildSubmitResult> {\\n  const taskId = `task_${randomUUID().slice(0, 8)}`;\\n  const runId = randomUUID();\\n  const submittedAt = new Date().toISOString();\\n\\n  // Run pre-execution gates (ambiguity + decomposition)\\n  const gateResult = await ctx.coordinator.submitWithGates({\\n    runId,\\n    input: prompt,\\n    exclusions,\\n    ...(repoPath ? { projectRoot: repoPath } : {}),\\n  });\\n\\n  if (gateResult.kind === \\\"needs_clarification\\\") {\\n    console.log(`[tasks] clarification needed for prompt: \\\"${prompt.slice(0, 80)}\\\"`);\\n    return { kind: \\\"needs_clarification\\\", question: gateResult.question };\\n  }\\n\\n  if (gateResult.kind === \\\"needs_decomposition\\\") {\\n    console.log(`[tasks] decomposition needed — ${(gateResult.plan as any).waves?.length ?? 0} wave(s)`);\\n    return {\\n      kind: \\\"needs_decomposition\\\",\\n      taskId: gateResult.taskId,\\n      plan: gateResult.plan,\\n      message: gateResult.message,\\n    };\\n  }\\n\\n  // Gate passed — execution started\\n  const tracked: TrackedRun = {\\n    taskId,\\n    runId,\\n    status: \\\"queued\\\",\\n    prompt,\\n    submittedAt,\\n    completedAt: null,\\n    receipt: null,\\n    error: null,\\n  };\\n  trackedRuns.set(taskId, tracked);\\n  await ctx.receiptStore.registerTask({\\n    taskId,\\n    runId,\\n    prompt: tracked.prompt,\\n    submittedAt,\\n  });\\n  tracked.status = \\\"running\\\";\\n  void ctx.receiptStore.updateTask(taskId, { status: \\\"running\\\" }).catch((err: unknown) =>\\n    console.error(\\\"[tasks] receiptStore update failed:\\\", err),\\n  );\\n\\n  ctx.eventBus.emit({\\n    type: \\\"run_started\\\",\\n    payload: { taskId, runId, prompt: tracked.prompt, status: \\\"running\\\", repoPath: repoPath ?? null },\\n  });\\n\\n  console.log(`[tasks] coordinator executing for taskId=${taskId} (projectRoot=${repoPath ?? \\\"(default)\\\"})...`);\\n\\n  // The receipt promise is already running from submitWithGates\\n  gateResult.receipt.then((receipt) => {\\n    console.log(`[tasks] coordinator.submit resolved: taskId=${taskId}, verdict=${receipt.verdict}, cost=$${receipt.totalCost.estimatedCostUsd}`);\\n    tracked.runId = receipt.runId;\\n    tracked.status =\\n      receipt.verdict === \\\"success\\\" ? \\\"complete\\\" :\\n      receipt.verdict === \\\"partial\\\" ? \\\"partial\\\" :\\n      receipt.verdict === \\\"aborted\\\" ? \\\"cancelled\\\" : \\\"failed\\\";\\n    tracked.completedAt = new Date().toISOString();\\n    tracked.receipt = receipt;\\n    void ctx.receiptStore.updateTask(taskId, {\\n      runId: receipt.runId,\\n      status: tracked.status,\\n      completedAt: tracked.completedAt,\\n      error: null,\\n    }).catch((err: unknown) =>\\n      console.error(\\\"[tasks] receiptStore update failed:\\\", err),\\n    );\\n\\n    ctx.eventBus.emit({\\n      type: \\\"run_complete\\\",\\n      payload: {\\n        taskId,\\n        runId: receipt.runId,\\n        verdict: receipt.verdict,\\n        totalCostUsd: receipt.totalCost.estimatedCostUsd,\\n        durationMs: receipt.durationMs,\\n        executionVerified: receipt.executionVerified,\\n        executionReason: receipt.executionGateReason,\\n      },\\n    });\\n\\n    ctx.eventBus.emit({\\n      type: \\\"run_receipt\\\",\\n      payload: { taskId, runId: receipt.runId, receiptId: receipt.id, receipt },\\n    });\\n  }).catch((err) => {\\n    console.error(\\\"═══ COORDINATOR SUBMIT FAILED ═══\\\");\\n    console.error(\\\"taskId:\\\", taskId);\\n    console.error(\\\"prompt:\\\", tracked.prompt.slice(0, 200));\\n    console.error(\\\"repoPath:\\\", repoPath ?? \\\"(default)\\\");\\n    console.error(\\\"error:\\\", err instanceof Error ? err.message : err);\\n    console.error(\\\"stack:\\\", err instanceof Error ? err.stack : \\\"\\\");\\n    console.error(\\\"═════════════════════════════════\\\");\\n\\n    tracked.status = \\\"failed\\\";\\n    tracked.completedAt = new Date().toISOString();\\n    tracked.error = err instanceof Error ? err.message : String(err);\\n    void ctx.receiptStore.updateTask(taskId, {\\n      status: \\\"failed\\\",\\n      completedAt: tracked.completedAt,\\n      error: tracked.error,\\n    }).catch((err: unknown) =>\\n      console.error(\\\"[tasks] receiptStore update failed:\\\", err),\\n    );\\n\\n    ctx.eventBus.emit({\\n      type: \\\"run_complete\\\",\\n      payload: {\\n        taskId,\\n        runId,\\n        verdict: \\\"failed\\\",\\n        error: tracked.error,\\n        executionVerified: false,\\n      },\\n    });\\n  });\\n\\n  return { kind: \\\"running\\\", taskId, runId, prompt, repoPath: repoPath ?? null };\\n}\\n\\n/**\\n * Find the most recent tracked run so the unified Loqui route can\\n * reconstruct the \\\"continuation\\\" prompt for a resume_run intent.\\n * Returns null when the session has no prior runs — the classifier\\n * already guards against this but the handler double-checks so a\\n * stale client context cannot spawn a resume against nothing.\\n */\\nfunction findLatestTrackedRun(): TrackedRun | null {\\n  let latest: TrackedRun | null = null;\\n  for (const run of trackedRuns.values()) {\\n    if (!latest) {\\n      latest = run;\\n      continue;\\n    }\\n    if (run.submittedAt > latest.submittedAt) {\\n      latest = run;\\n    }\\n  }\\n  return latest;\\n}\\n\\nasync function findLatestKnownRun(ctx: ServerContext): Promise<{\\n  taskId: string | null;\\n  runId: string;\\n  prompt: string;\\n  status: string;\\n} | null> {\\n  const tracked = findLatestTrackedRun();\\n  if (tracked) {\\n    return {\\n      taskId: tracked.taskId,\\n      runId: tracked.runId,\\n      prompt: tracked.prompt,\\n      status: tracked.status,\\n    };\\n  }\\n\\n  const recent = await ctx.receiptStore.listRuns(10);\\n  for (const entry of recent) {\\n    const receipt = await ctx.receiptStore.getRun(entry.runId);\\n    if (!receipt) continue;\\n    const task = await ctx.receiptStore.getTaskByRunId(entry.runId);\\n    return {\\n      taskId: task?.taskId ?? null,\\n      runId: entry.runId,\\n      prompt: task?.prompt ?? receipt.prompt,\\n      status: receipt.status,\\n    };\\n  }\\n\\n  return null;\\n}\\n\\nasync function findKnownRunById(\\n  ctx: ServerContext,\\n  id: string | null | undefined,\\n): Promise<{\\n  taskId: string | null;\\n  runId: string;\\n  prompt: string;\\n  status: string;\\n} | null> {\\n  if (!id) return null;\\n  const task = await ctx.receiptStore.getTask(id);\\n  if (task) {\\n    const receipt = await ctx.receiptStore.getRun(task.runId);\\n    return {\\n      taskId: task.taskId,\\n      runId: task.runId,\\n      prompt: task.prompt || receipt?.prompt || \\\"\\\",\\n      status: receipt?.status ?? task.status,\\n    };\\n  }\\n  const byRun = await ctx.receiptStore.getTaskByRunId(id);\\n  if (byRun) {\\n    const receipt = await ctx.receiptStore.getRun(byRun.runId);\\n    return {\\n      taskId: byRun.taskId,\\n      runId: byRun.runId,\\n      prompt: byRun.prompt || receipt?.prompt || \\\"\\\",\\n      status: receipt?.status ?? byRun.status,\\n    };\\n  }\\n  const receipt = await ctx.receiptStore.getRun(id);\\n  if (receipt) {\\n    return {\\n      taskId: null,\\n      runId: receipt.runId,\\n      prompt: receipt.prompt,\\n      status: receipt.status,\\n    };\\n  }\\n  return null;\\n}\\n\\n// ─── Routes ──────────────────────────────────────────────────────────\\n\\nexport const taskRoutes: FastifyPluginAsync = async (fastify) => {\\n  const ctx = (): ServerContext => fastify.ctx;\\n\\n  fastify.get<{\\n    Querystring: {\\n      limit?: string | number;\\n      sort?: string;\\n      status?: string;\\n    };\\n  }>(\\n    \\\"/\\\",\\n    async (request, reply) => {\\n      const rawLimit = Number(request.query.limit ?? 20);\\n      const limit = Number.isFinite(rawLimit)\\n        ? Math.max(1, Math.min(Math.trunc(rawLimit), 100))\\n        : 20;\\n      const sort = String(request.query.sort ?? \\\"desc\\\").toLowerCase();\\n      const statusFilter = typeof request.query.status === \\\"string\\\" && request.query.status.trim().length > 0\\n        ? request.query.status.trim()\\n        : undefined;\\n\\n      const persisted = await ctx().receiptStore.listRuns(limit * 2, statusFilter);\\n      const tasks = await Promise.all(\\n        persisted.map(async (entry) => {\\n          const task = await ctx().receiptStore.getTaskByRunId(entry.runId);\\n          return {\\n            task_id: task?.taskId ?? null,\\n            run_id: entry.runId,\\n            prompt: task?.prompt ?? entry.prompt,\\n            submitted_at: task?.submittedAt ?? entry.createdAt,\\n            completed_at: task?.completedAt ?? entry.completedAt,\\n            status: task?.status ?? entry.status,\\n            verdict: entry.finalClassification ?? entry.status,\\n            cost: entry.costUsd,\\n            confidence: entry.confidence,\\n            summary: entry.summary,\\n          };\\n        }),\\n      );\\n\\n      tasks.sort((a, b) => {\\n        const left = a.submitted_at ?? \\\"\\\";\\n        const right = b.submitted_at ?? \\\"\\\";\\n        return sort === \\\"asc\\\"\\n          ? (left < right ? -1 : left > right ? 1 : 0)\\n          : (left < right ? 1 : left > right ? -1 : 0);\\n      });\\n\\n      reply.send({\\n        tasks: tasks.slice(0, limit),\\n        count: Math.min(tasks.length, limit),\\n        sort,\\n      });\\n    },\\n  );\\n\\n  async function cancelTrackedTask(id: string): Promise<{\\n    ok: boolean;\\n    taskId: string;\\n    runId: string | null;\\n    message: string;\\n  }> {\\n    const tracked = trackedRuns.get(id);\\n    if (tracked && tracked.runId) {\\n      const cancelled = ctx().coordinator.cancel(tracked.runId);\\n      if (cancelled) {\\n        tracked.status = \\\"cancelled\\\";\\n        tracked.completedAt = new Date().toISOString();\\n        tracked.error = \\\"Cancelled by user\\\";\\n        await ctx().receiptStore.updateTask(tracked.taskId, {\\n          status: \\\"cancelled\\\",\\n          completedAt: tracked.completedAt,\\n          error: tracked.error,\\n        });\\n        ctx().eventBus.emit({\\n          type: \\\"run_cancelled\\\",\\n          payload: {\\n            taskId: tracked.taskId,\\n            runId: tracked.runId,\\n            status: \\\"cancelled\\\",\\n            verdict: \\\"cancelled\\\",\\n            completedAt: tracked.completedAt,\\n            error: tracked.error,\\n          },\\n        });\\n        return {\\n          ok: true,\\n          taskId: tracked.taskId,\\n          runId: tracked.runId,\\n          message: \\\"Run cancellation requested\\\",\\n        };\\n      }\\n    }\\n\\n    const persistedTask = await ctx().receiptStore.getTask(id) ?? await ctx().receiptStore.getTaskByRunId(id);\\n    if (persistedTask) {\\n      const cancelled = ctx().coordinator.cancel(persistedTask.runId);\\n      if (cancelled) {\\n        const completedAt = new Date().toISOString();\\n        await ctx().receiptStore.updateTask(persistedTask.taskId, {\\n          status: \\\"cancelled\\\",\\n          completedAt,\\n          error: \\\"Cancelled by user\\\",\\n        });\\n        const trackedPersisted = trackedRuns.get(persistedTask.taskId);\\n        if (trackedPersisted) {\\n          trackedPersisted.status = \\\"cancelled\\\";\\n          trackedPersisted.completedAt = completedAt;\\n          trackedPersisted.error = \\\"Cancelled by user\\\";\\n        }\\n        ctx().eventBus.emit({\\n          type: \\\"run_cancelled\\\",\\n          payload: {\\n            taskId: persistedTask.taskId,\\n            runId: persistedTask.runId,\\n            status: \\\"cancelled\\\",\\n            verdict: \\\"cancelled\\\",\\n            completedAt,\\n            error: \\\"Cancelled by user\\\",\\n          },\\n        });\\n        return {\\n          ok: true,\\n          taskId: persistedTask.taskId,\\n          runId: persistedTask.runId,\\n          message: \\\"Run cancellation requested\\\",\\n        };\\n      }\\n    }\\n\\n    const cancelled = ctx().coordinator.cancel(id);\\n    if (cancelled) {\\n      const completedAt = new Date().toISOString();\\n      ctx().eventBus.emit({\\n        type: \\\"run_cancelled\\\",\\n        payload: {\\n          taskId: id,\\n          runId: id,\\n          status: \\\"cancelled\\\",\\n          verdict: \\\"cancelled\\\",\\n          completedAt,\\n          error: \\\"Cancelled by user\\\",\\n        },\\n      });\\n      return {\\n        ok: true,\\n        taskId: id,\\n        runId: id,\\n        message: \\\"Run cancellation requested\\\",\\n      };\\n    }\\n\\n    return {\\n      ok: false,\\n      taskId: id,\\n      runId: null,\\n      message: `No active run found with ID \\\"${id}\\\"`,\\n    };\\n  }\\n\\n  function toTaskStatus(\\n    status: import(\\\"../../core/receipt-store.js\\\").PersistentRunStatus,\\n    finalClassification?: string | null,\\n  ): TrackedRun[\\\"status\\\"] {\\n    // PARTIAL_SUCCESS maps to \\\"partial\\\" regardless of the underlying status\\n    if (finalClassification === \\\"PARTIAL_SUCCESS\\\") return \\\"partial\\\";\\n    switch (status) {\\n      // Active states\\n      case \\\"PROPOSED\\\":\\n      case \\\"RUNNING\\\":\\n      case \\\"EXECUTING_IN_WORKSPACE\\\":\\n      case \\\"VERIFICATION_PENDING\\\":\\n        return \\\"running\\\";\\n      case \\\"AWAITING_APPROVAL\\\":\\n      case \\\"DISAGREEMENT_HOLD\\\":\\n        return \\\"running\\\";\\n      // Terminal success\\n      case \\\"COMPLETE\\\":\\n      case \\\"VERIFIED_PASS\\\":\\n      case \\\"READY_FOR_PROMOTION\\\":\\n        return \\\"complete\\\";\\n      // Cancelled\\n      case \\\"ABORTED\\\":\\n      case \\\"INTERRUPTED\\\":\\n        return \\\"cancelled\\\";\\n      // Failures\\n      case \\\"REJECTED\\\":\\n      case \\\"CRASHED\\\":\\n      case \\\"EXECUTION_ERROR\\\":\\n      case \\\"CLEANUP_ERROR\\\":\\n      case \\\"FAILED\\\":\\n      case \\\"VERIFIED_FAIL\\\":\\n      case \\\"CRUCIBULUM_FAIL\\\":\\n      default:\\n        return \\\"failed\\\";\\n    }\\n  }\\n\\n  fastify.post<{ Body: LoquiBody }>(\\n    \\\"/loqui\\\",\\n    {\\n      schema: {\\n        body: {\\n          type: \\\"object\\\",\\n          required: [\\\"question\\\", \\\"repoPath\\\"],\\n          properties: {\\n            question: { type: \\\"string\\\", minLength: 1 },\\n            repoPath: { type: \\\"string\\\", minLength: 1 },\\n          },\\n        },\\n      },\\n    },\\n    async (request: FastifyRequest<{ Body: LoquiBody }>, reply: FastifyReply) => {\\n      const { question, repoPath } = request.body;\\n\\n      if (!existsSync(repoPath)) {\\n        reply.code(400).send({\\n          error: \\\"Bad request\\\",\\n          message: `repoPath does not exist on this host: ${repoPath}`,\\n        });\\n        return;\\n      }\\n\\n      const answer = await askLoqui(question, repoPath);\\n      reply.send({ answer });\\n    }\\n  );\\n\\n  /**\\n   * POST /tasks/loqui/unified — Unified Loqui intent routing.\\n   *\\n   * Accepts one freeform input string, runs it through the\\n   * classifier + router, and dispatches to the correct backend path.\\n   * The UI sends every Loqui chat message here — there is no more\\n   * \\\"mode\\\" to pick at submit time.\\n   *\\n   * Response shape (always the same top-level wrapper):\\n   *   {\\n   *     route: \\\"build\\\" | \\\"answer\\\" | \\\"clarify\\\",\\n   *     intent, label, reason, confidence, signals,\\n   *     ...plus a route-specific payload:\\n   *       build   → { task_id, run_id, prompt, repo_path }\\n   *       answer  → { answer }\\n   *       clarify → { clarification }\\n   *   }\\n   *\\n   * The `signals` field exists so the UI (and later audit tooling)\\n   * can show *why* Loqui picked the route it picked — this preserves\\n   * the inspectability constraint from the execution-truth work.\\n   */\\n  fastify.post<{ Body: LoquiUnifiedBody }>(\\n    \\\"/loqui/unified\\\",\\n    {\\n      schema: {\\n        body: {\\n          type: \\\"object\\\",\\n          required: [\\\"input\\\", \\\"repoPath\\\"],\\n          properties: {\\n            input: { type: \\\"string\\\", minLength: 1 },\\n            repoPath: { type: \\\"string\\\", minLength: 1 },\\n            context: {\\n              type: \\\"object\\\",\\n              additionalProperties: true,\\n              properties: {\\n                activeRunId: { type: [\\\"string\\\", \\\"null\\\"] },\\n                lastRunId: { type: [\\\"string\\\", \\\"null\\\"] },\\n                lastRunVerdict: { type: [\\\"string\\\", \\\"null\\\"] },\\n                previousMessageWasBuild: { type: \\\"boolean\\\" },\\n              },\\n            },\\n          },\\n        },\\n      },\\n    },\\n    async (request: FastifyRequest<{ Body: LoquiUnifiedBody }>, reply: FastifyReply) => {\\n      const { input, repoPath } = request.body;\\n      const routerContext: LoquiIntentContext = request.body.context ?? {};\\n\\n      if (!existsSync(repoPath)) {\\n        reply.code(400).send({\\n          error: \\\"Bad request\\\",\\n          message: `repoPath does not exist on this host: ${repoPath}`,\\n        });\\n        return;\\n      }\\n\\n      const decision: LoquiRouteDecision = routeLoquiInput({ input, context: routerContext });\\n      console.log(\\n        `[tasks] /loqui/unified: action=${decision.action} intent=${decision.intent} ` +\\n        `label=${decision.label} confidence=${decision.confidence.toFixed(2)} ` +\\n        `reason=\\\"${decision.reason}\\\" signals=${decision.signals.length}`,\\n      );\\n\\n      // Base envelope every response shares. Gives the UI a stable\\n      // shape to hang its intent badge / signal audit off of, no\\n      // matter which backend path actually ran.\\n      const envelope = {\\n        route: decision.action,\\n        intent: decision.intent,\\n        label: decision.label,\\n        reason: decision.reason,\\n        confidence: decision.confidence,\\n        signals: [...decision.signals],\\n        original_input: decision.originalInput,\\n      };\\n\\n      switch (decision.action) {\\n        case \\\"build\\\": {\\n          const result = await submitBuildTask(ctx(), decision.effectivePrompt, repoPath, undefined);\\n          if (result.kind === \\\"needs_clarification\\\") {\\n            reply.send({\\n              ...envelope,\\n              route: \\\"clarify\\\",\\n              status: \\\"needs_clarification\\\",\\n              clarification: result.question,\\n            });\\n            return;\\n          }\\n          if (result.kind === \\\"needs_decomposition\\\") {\\n            reply.code(202).send({\\n              ...envelope,\\n              status: \\\"needs_decomposition\\\",\\n              task_id: result.taskId,\\n              plan: result.plan,\\n              message: result.message,\\n            });\\n            return;\\n          }\\n          reply.code(202).send({\\n            ...envelope,\\n            task_id: result.taskId,\\n            run_id: result.runId,\\n            prompt: result.prompt,\\n            repo_path: result.repoPath,\\n            status: \\\"running\\\",\\n            message: \\\"Build task submitted. Watch the worker grid and Lumen log for progress.\\\",\\n          });\\n          return;\\n        }\\n\\n        case \\\"resume\\\": {\\n          // Stitch the new input onto the most recent tracked run's\\n          // prompt so the Coordinator sees a self-contained request.\\n          // If no prior run exists on the server (e.g. because this\\n          // server was restarted since the UI learned about it), we\\n          // fall back to treating the input as a bare build rather\\n          // than failing — the user's intent to \\\"continue\\\" is clear\\n          // even if we don't have the history to reference.\\n          const requestedPriorId = routerContext.activeRunId ?? routerContext.lastRunId ?? null;\\n          const prior =\\n            await findKnownRunById(ctx(), requestedPriorId) ??\\n            await findLatestKnownRun(ctx());\\n          const stitched = prior\\n            ? `Continue the prior build (${prior.runId}): \\\"${prior.prompt}\\\". Follow-up instruction: ${decision.originalInput}`\\n            : decision.originalInput;\\n          const result = await submitBuildTask(ctx(), stitched, repoPath, undefined);\\n          if (result.kind === \\\"needs_clarification\\\") {\\n            reply.send({\\n              ...envelope,\\n              route: \\\"clarify\\\",\\n              status: \\\"needs_clarification\\\",\\n              clarification: result.question,\\n            });\\n            return;\\n          }\\n          if (result.kind === \\\"needs_decomposition\\\") {\\n            reply.code(202).send({\\n              ...envelope,\\n              status: \\\"needs_decomposition\\\",\\n              task_id: result.taskId,\\n              plan: result.plan,\\n              message: result.message,\\n            });\\n            return;\\n          }\\n          reply.code(202).send({\\n            ...envelope,\\n            task_id: result.taskId,\\n            run_id: result.runId,\\n            prompt: result.prompt,\\n            repo_path: result.repoPath,\\n            resumed_from: prior?.runId ?? null,\\n            status: \\\"running\\\",\\n            message: prior\\n              ? `Resuming from ${prior.runId}. New build task submitted.`\\n              : \\\"No prior run found in persisted history — submitted as a fresh build.\\\",\\n          });\\n          return;\\n        }\\n\\n        case \\\"answer\\\": {\\n          const answer = await askLoqui(decision.effectivePrompt, repoPath);\\n          reply.send({ ...envelope, answer });\\n          return;\\n        }\\n\\n        case \\\"dry_run\\\": {\\n          // Preflight + Dry Run System v1 — grounded structured\\n          // plan produced by generateDryRun. Nothing is written,\\n          // no worker runs. The plan reuses every planning\\n          // primitive the Coordinator uses at runtime, so the\\n          // steps the user sees here match what would happen if\\n          // they submitted the same request for real.\\n          const plan = generateDryRun({ input: decision.originalInput, projectRoot: repoPath });\\n          reply.send({ ...envelope, plan });\\n          return;\\n        }\\n\\n        case \\\"clarify\\\":\\n        default: {\\n          reply.send({ ...envelope, clarification: decision.clarification });\\n          return;\\n        }\\n      }\\n    }\\n  );\\n\\n  /**\\n   * POST /tasks/dry-run — Direct dry-run entry point.\\n   *\\n   * Skips the classifier and produces a structured dry-run plan\\n   * from a raw prompt + repoPath. Used by API clients that\\n   * already know they want a plan (no natural-language gate).\\n   * Response shape mirrors the `dry_run` action from the\\n   * unified route: { plan: DryRunPlan }.\\n   */\\n  fastify.post<{ Body: { input: string; repoPath: string } }>(\\n    \\\"/dry-run\\\",\\n    {\\n      schema: {\\n        body: {\\n          type: \\\"object\\\",\\n          required: [\\\"input\\\", \\\"repoPath\\\"],\\n          properties: {\\n            input: { type: \\\"string\\\", minLength: 1 },\\n            repoPath: { type: \\\"string\\\", minLength: 1 },\\n          },\\n        },\\n      },\\n    },\\n    async (request, reply) => {\\n      const { input, repoPath } = request.body;\\n      if (!existsSync(repoPath)) {\\n        reply.code(400).send({\\n          error: \\\"Bad request\\\",\\n          message: `repoPath does not exist on this host: ${repoPath}`,\\n        });\\n        return;\\n      }\\n      const plan = generateDryRun({ input, projectRoot: repoPath });\\n      reply.send({ plan });\\n    }\\n  );\\n\\n  /**\\n   * POST /tasks — Submit a new build task.\\n   *\\n   * Calls coordinator.submit() and tracks the run.\\n   * Returns immediately with task_id + run_id. The run executes async.\\n   * Client should subscribe on WebSocket with { type: \\\"subscribe\\\", runId }.\\n   *\\n   * The optional `repoPath` field in the body lets the caller target a\\n   * specific local repo as the project root for this build. The Coordinator\\n   * uses it as the effective projectRoot — workers see it via\\n   * assignment.projectRoot, gitCommit runs with cwd=repoPath, and the\\n   * IntegrationJudge normalizes deliverable paths against it. When omitted,\\n   * the Coordinator falls back to its own boot-time config.projectRoot\\n   * (typically the API server's cwd).\\n   */\\n  fastify.post<{ Body: SubmitBody }>(\\n    \\\"/\\\",\\n    {\\n      schema: {\\n        body: {\\n          type: \\\"object\\\",\\n          properties: {\\n            prompt: { type: \\\"string\\\", minLength: 1 },\\n            input: { type: \\\"string\\\", minLength: 1 },\\n            repoPath: { type: \\\"string\\\" },\\n            exclusions: { type: \\\"array\\\", items: { type: \\\"string\\\" } },\\n            quality_bar: { type: \\\"string\\\", enum: [\\\"minimal\\\", \\\"standard\\\", \\\"hardened\\\"] },\\n          },\\n        },\\n      },\\n    },\\n    async (request: FastifyRequest<{ Body: SubmitBody }>, reply: FastifyReply) => {\\n      const prompt = request.body.prompt || request.body.input;\\n      const repoPath = request.body.repoPath;\\n      console.log(\\\"[tasks] POST /tasks received:\\\", { prompt: prompt?.slice(0, 80), repoPath });\\n\\n      if (!prompt || !prompt.trim()) {\\n        reply.code(400).send({\\n          error: \\\"Bad request\\\",\\n          message: \\\"Either 'prompt' or 'input' field is required\\\",\\n        });\\n        return;\\n      }\\n\\n      // Validate repoPath if provided. The CLI does its own existsSync check\\n      // but we re-validate at the API boundary as defense-in-depth — a\\n      // misconfigured client (or a direct curl) might send a path that\\n      // doesn't exist on this host. Failing here gives a clear error\\n      // instead of letting the Coordinator throw mid-build.\\n      if (repoPath !== undefined && repoPath.length > 0) {\\n        if (!existsSync(repoPath)) {\\n          console.warn(`[tasks] rejecting POST: repoPath does not exist: ${repoPath}`);\\n          reply.code(400).send({\\n            error: \\\"Bad request\\\",\\n            message: `repoPath does not exist on this host: ${repoPath}`,\\n          });\\n          return;\\n        }\\n      }\\n\\n      const result = await submitBuildTask(ctx(), prompt.trim(), repoPath, request.body.exclusions);\\n\\n      if (result.kind === \\\"needs_clarification\\\") {\\n        reply.code(202).send({\\n          status: \\\"needs_clarification\\\",\\n          question: result.question,\\n        });\\n        return;\\n      }\\n\\n      if (result.kind === \\\"needs_decomposition\\\") {\\n        reply.code(202).send({\\n          status: \\\"needs_decomposition\\\",\\n          task_id: result.taskId,\\n          plan: result.plan,\\n          message: result.message,\\n        });\\n        return;\\n      }\\n\\n      reply.code(202).send({\\n        task_id: result.taskId,\\n        run_id: result.runId,\\n        status: \\\"running\\\",\\n        prompt: result.prompt,\\n        repo_path: result.repoPath,\\n        message: \\\"Task submitted. Connect to /ws and subscribe to receive live updates.\\\",\\n      });\\n    }\\n  );\\n\\n  /**\\n   * GET /tasks/:id — Get task status and current run state.\\n   */\\n  fastify.get<{ Params: TaskParams }>(\\n    \\\"/:id\\\",\\n    async (request: FastifyRequest<{ Params: TaskParams }>, reply: FastifyReply) => {\\n      const { id } = request.params;\\n      const tracked = trackedRuns.get(id);\\n\\n      if (tracked) {\\n        const activeRun = ctx().coordinator.getRunStatus(tracked.runId);\\n        const completedTasks = activeRun ? activeRun.run.tasks.filter((task) => task.status === \\\"completed\\\").length : 0;\\n        const failedTasks = activeRun ? activeRun.run.tasks.filter((task) => task.status === \\\"failed\\\").length : 0;\\n\\n        // If the coordinator has resolved the receipt, extract extended fields\\n        const receipt = tracked.receipt as any;\\n        reply.send({\\n          task_id: tracked.taskId,\\n          run_id: tracked.runId,\\n          status: tracked.status,\\n          verdict: receipt?.finalClassification ?? receipt?.humanSummary?.classification ?? null,\\n          summary: receipt?.humanSummary?.headline ?? null,\\n          confidence: receipt?.confidence?.overall ?? null,\\n          cost: receipt?.totalCost?.estimatedCostUsd ?? null,\\n          prompt: tracked.prompt,\\n          submitted_at: tracked.submittedAt,\\n          completed_at: tracked.completedAt,\\n          error: tracked.error,\\n          active_run: Boolean(activeRun),\\n          progress: activeRun ? {\\n            phase: activeRun.run.phase,\\n            completed_tasks: completedTasks,\\n            failed_tasks: failedTasks,\\n            total_tasks: activeRun.run.tasks.length,\\n            total_cost: activeRun.run.totalCost,\\n          } : null,\\n        });\\n        return;\\n      }\\n\\n      const persistedTask = await ctx().receiptStore.getTask(id) ?? await ctx().receiptStore.getTaskByRunId(id);\\n      if (persistedTask) {\\n        const persistedRun = await ctx().receiptStore.getRun(persistedTask.runId);\\n        const activeRun = ctx().coordinator.getRunStatus(persistedTask.runId);\\n        const completedTasks = activeRun ? activeRun.run.tasks.filter((task) => task.status === \\\"completed\\\").length : 0;\\n        const failedTasks = activeRun ? activeRun.run.tasks.filter((task) => task.status === \\\"failed\\\").length : 0;\\n        reply.send({\\n          task_id: persistedTask.taskId,\\n          run_id: persistedTask.runId,\\n          status: persistedRun\\n            ? toTaskStatus(persistedRun.status, persistedRun.finalClassification)\\n            : persistedTask.status,\\n          verdict: persistedRun?.finalClassification ?? null,\\n          summary: persistedRun?.taskSummary ?? null,\\n          confidence: persistedRun?.confidence?.overall ?? null,\\n          cost: persistedRun?.totalCost?.estimatedCostUsd ?? null,\\n          prompt: persistedTask.prompt,\\n          submitted_at: persistedTask.submittedAt,\\n          completed_at: persistedRun?.completedAt ?? persistedTask.completedAt,\\n          error: persistedRun?.errors?.[0] ?? persistedTask.error,\\n          active_run: Boolean(activeRun),\\n          progress: activeRun ? {\\n            phase: activeRun.run.phase,\\n            completed_tasks: completedTasks,\\n            failed_tasks: failedTasks,\\n            total_tasks: activeRun.run.tasks.length,\\n            total_cost: activeRun.run.totalCost,\\n          } : persistedRun ? {\\n            phase: persistedRun.phase,\\n            completed_tasks: persistedRun.workerEvents.filter((event: any) => event.status === \\\"completed\\\").length,\\n            failed_tasks: persistedRun.workerEvents.filter((event: any) => event.status === \\\"failed\\\").length,\\n            total_tasks: persistedRun.workerEvents.length,\\n            total_cost: persistedRun.totalCost,\\n          } : null,\\n        });\\n        return;\\n      }\\n\\n      // Fallback: search event history\\n      const recentEvents = ctx().eventBus.recentEvents(100);\\n      const taskEvents = recentEvents.filter(\\n        (e) => (e.payload as any).taskId === id || (e.payload as any).runId === id\\n      );\\n\\n      if (taskEvents.length === 0) {\\n        reply.code(404).send({\\n          error: \\\"Not found\\\",\\n          message: `No task or run found with ID \\\"${id}\\\"`,\\n        });\\n        return;\\n      }\\n\\n      const lastEvent = taskEvents[taskEvents.length - 1];\\n      const isComplete = lastEvent.type === \\\"run_complete\\\" || lastEvent.type === \\\"run_receipt\\\";\\n      const runId = (lastEvent.payload as any).runId ?? id;\\n\\n      reply.send({\\n        task_id: id,\\n        run_id: runId,\\n        status: isComplete ? \\\"complete\\\" : \\\"running\\\",\\n        phase: lastEvent.type,\\n        active_run: !isComplete,\\n        progress: null,\\n        last_event: lastEvent,\\n        event_count: taskEvents.length,\\n        events: taskEvents,\\n      });\\n    }\\n  );\\n\\n  /**\\n   * GET /tasks/:id/receipts — Get the full receipt bundle for a completed task.\\n   */\\n  fastify.get<{ Params: TaskParams }>(\\n    \\\"/:id/receipts\\\",\\n    async (request: FastifyRequest<{ Params: TaskParams }>, reply: FastifyReply) => {\\n      const { id } = request.params;\\n\\n      // Check tracked runs first\\n      const tracked = trackedRuns.get(id);\\n      if (tracked?.receipt) {\\n        reply.send({ task_id: id, run_id: tracked.runId, receipt: tracked.receipt });\\n        return;\\n      }\\n\\n      const task = await ctx().receiptStore.getTask(id) ?? await ctx().receiptStore.getTaskByRunId(id);\\n      const persisted = await ctx().receiptStore.getRun(task?.runId ?? id);\\n      if (persisted) {\\n        reply.send({ task_id: task?.taskId ?? id, run_id: persisted.runId, receipt: persisted.finalReceipt ?? persisted });\\n        return;\\n      }\\n\\n      // Fallback to event history\\n      const recentEvents = ctx().eventBus.recentEvents(200);\\n      const receiptEvent = recentEvents.find(\\n        (e) =>\\n          e.type === \\\"run_receipt\\\" &&\\n          ((e.payload as any).taskId === id || (e.payload as any).runId === id)\\n      );\\n\\n      if (!receiptEvent) {\\n        reply.code(404).send({\\n          error: \\\"Not found\\\",\\n          message: `No receipt found for task \\\"${id}\\\". Task may still be running.`,\\n        });\\n        return;\\n      }\\n\\n      reply.send({\\n        task_id: id,\\n        receipt: receiptEvent.payload,\\n      });\\n    }\\n  );\\n\\n  /**\\n   * POST /tasks/:id/cancel — Cancel a running task.\\n   */\\n  fastify.post<{ Params: TaskParams }>(\\n    \\\"/:id/cancel\\\",\\n    async (request: FastifyRequest<{ Params: TaskParams }>, reply: FastifyReply) => {\\n      const { id } = request.params;\\n      const result = await cancelTrackedTask(id);\\n      if (!result.ok) {\\n        reply.code(404).send({\\n          error: \\\"Not found\\\",\\n          message: result.message,\\n        });\\n        return;\\n      }\\n      reply.send({\\n        task_id: result.taskId,\\n        run_id: result.runId,\\n        status: \\\"cancelled\\\",\\n        message: result.message,\\n      });\\n    }\\n  );\\n\\n  /**\\n   * POST /tasks/:id/approve — Approve a pending decomposition plan and\\n   * resume execution.\\n   */\\n  fastify.post<{ Params: TaskParams }>(\\n    \\\"/:id/approve\\\",\\n    async (request: FastifyRequest<{ Params: TaskParams }>, reply: FastifyReply) => {\\n      const { id } = request.params;\\n      const result = ctx().coordinator.approvePlan(id);\\n\\n      if (!result) {\\n        reply.code(404).send({\\n          error: \\\"Not found\\\",\\n          message: `No pending plan found with ID \\\"${id}\\\"`,\\n        });\\n        return;\\n      }\\n\\n      const taskId = `task_${randomUUID().slice(0, 8)}`;\\n      const runId = randomUUID();\\n      const submittedAt = new Date().toISOString();\\n\\n      const tracked: TrackedRun = {\\n        taskId,\\n        runId,\\n        status: \\\"running\\\",\\n        prompt: `(approved plan ${id})`,\\n        submittedAt,\\n        completedAt: null,\\n        receipt: null,\\n        error: null,\\n      };\\n      trackedRuns.set(taskId, tracked);\\n\\n      result.receipt.then((receipt) => {\\n        tracked.runId = receipt.runId;\\n        tracked.status =\\n          receipt.verdict === \\\"success\\\" ? \\\"complete\\\" :\\n          receipt.verdict === \\\"partial\\\" ? \\\"partial\\\" :\\n          receipt.verdict === \\\"aborted\\\" ? \\\"cancelled\\\" : \\\"failed\\\";\\n        tracked.completedAt = new Date().toISOString();\\n        tracked.receipt = receipt;\\n\\n        ctx().eventBus.emit({\\n          type: \\\"run_complete\\\",\\n          payload: {\\n            taskId,\\n            runId: receipt.runId,\\n            verdict: receipt.verdict,\\n            totalCostUsd: receipt.totalCost.estimatedCostUsd,\\n            durationMs: receipt.durationMs,\\n            executionVerified: receipt.executionVerified,\\n            executionReason: receipt.executionGateReason,\\n          },\\n        });\\n      }).catch((err) => {\\n        tracked.status = \\\"failed\\\";\\n        tracked.completedAt = new Date().toISOString();\\n        tracked.error = err instanceof Error ? err.message : String(err);\\n      });\\n\\n      reply.code(202).send({\\n        task_id: taskId,\\n        run_id: runId,\\n        status: \\\"running\\\",\\n        message: `Plan \\\"${id}\\\" approved. Execution started.`,\\n      });\\n    }\\n  );\\n\\n  /**\\n   * DELETE /tasks/:id — Cancel a running task.\\n   */\\n  fastify.delete<{ Params: TaskParams }>(\\n    \\\"/:id\\\",\\n    async (request: FastifyRequest<{ Params: TaskParams }>, reply: FastifyReply) => {\\n      const { id } = request.params;\\n      const result = await cancelTrackedTask(id);\\n      if (!result.ok) {\\n        reply.code(404).send({\\n          error: \\\"Not found\\\",\\n          message: result.message,\\n        });\\n        return;\\n      }\\n      reply.send({\\n        task_id: result.taskId,\\n        run_id: result.runId,\\n        status: \\\"cancelled\\\",\\n        message: result.message,\\n      });\\n    }\\n  );\\n\\n  /**\\n   * POST /tasks/:id/promote — Promote workspace changes to the source repo.\\n   * This is the final step: applies the workspace commit to the source\\n   * repository. Only works for runs that have been committed in their\\n   * workspace (status: READY_FOR_PROMOTION or VERIFIED_PASS).\\n   */\\n  fastify.post<{ Params: TaskParams; Body: { source_repo?: string } }>(\\n    \\\"/:id/promote\\\",\\n    async (request: FastifyRequest<{ Params: TaskParams; Body: { source_repo?: string } }>, reply: FastifyReply) => {\\n      const { id } = request.params;\\n      // Find the runId from the tracked task\\n      const tracked = trackedRuns.get(id);\\n      if (!tracked) {\\n        reply.code(404).send({ error: \\\"Not found\\\", message: `No task \\\"${id}\\\"` });\\n        return;\\n      }\\n      const result = await ctx().coordinator.promoteToSource(tracked.runId, request.body?.source_repo);\\n      if (!result.ok) {\\n        reply.code(400).send({ error: \\\"Promotion failed\\\", message: result.error });\\n        return;\\n      }\\n      reply.send({\\n        task_id: id,\\n        run_id: tracked.runId,\\n        status: \\\"promoted\\\",\\n        commit_sha: result.commitSha,\\n        message: \\\"Changes promoted to source repository\\\",\\n      });\\n    }\\n  );\\n};\\n\",\"lineCount\":1189},{\"path\":\"server/routes/config.ts\",\"content\":\"/**\\n * Config routes — Model assignment management.\\n *\\n * GET  /config/models — Return current model assignments\\n * POST /config/models — Update model assignments\\n *\\n * Persists to .aedis/model-config.json relative to project root.\\n * Falls back to the legacy .zendorium/model-config.json location on\\n * read so existing installs keep working after the rename. New writes\\n * always go to .aedis/.\\n */\\n\\nimport { readFileSync, writeFileSync, mkdirSync, existsSync } from \\\"fs\\\";\\nimport { join } from \\\"path\\\";\\nimport type { FastifyPluginAsync, FastifyRequest, FastifyReply } from \\\"fastify\\\";\\nimport type { ServerContext } from \\\"../index.js\\\";\\n\\n// ─── Types ───────────────────────────────────────────────────────────\\n\\nexport interface ModelAssignment {\\n  model: string;\\n  provider: string;\\n}\\n\\nexport interface ModelConfig {\\n  scout: ModelAssignment;\\n  builder: ModelAssignment;\\n  critic: ModelAssignment;\\n  verifier: ModelAssignment;\\n  integrator: ModelAssignment;\\n  escalation: ModelAssignment;\\n  coordinator: ModelAssignment;\\n}\\n\\n// ─── Defaults ────────────────────────────────────────────────────────\\n//\\n// IMPORTANT: a persisted .aedis/model-config.json file at the project\\n// root will OVERRIDE these defaults via loadModelConfig() below (with\\n// .zendorium/model-config.json as the legacy fallback). Changing the\\n// defaults here only affects projects that have no saved config. To\\n// change an active build's model selection, either delete that file or\\n// edit its `builder` / `critic` block directly.\\n//\\n// Per-role fallbacks (Builder + Critic) are NOT in this config — they\\n// are hardcoded in the worker constructors (workers/builder.ts and\\n// workers/critic.ts). The fallback chain logic lives in\\n// core/model-invoker.ts (invokeModelWithFallback).\\n//\\n// Builder default change history:\\n//   - was: claude-sonnet-4-6 / anthropic (briefly tried as primary, but\\n//          ModelStudio turned out to be slow rather than broken)\\n//   - now: qwen3.6-plus / modelstudio (with anthropic/claude-sonnet-4-6\\n//          as the worker-level fallback)\\n//\\n// Critic default change history:\\n//   - was: qwen3.5:9b / ollama\\n//   - now: claude-sonnet-4-6 / anthropic (with ollama/qwen3.5:9b as the\\n//          worker-level fallback) — Critic gates the pipeline so a stronger\\n//          model here pays for itself by catching issues before Verify.\\n\\nconst DEFAULT_MODEL_CONFIG: ModelConfig = {\\n  scout: { model: \\\"local\\\", provider: \\\"local\\\" },\\n  builder: { model: \\\"xiaomi/mimo-v2.5\\\", provider: \\\"openrouter\\\" },\\n  critic: { model: \\\"claude-sonnet-4-6\\\", provider: \\\"anthropic\\\" },\\n  verifier: { model: \\\"local\\\", provider: \\\"local\\\" },\\n  integrator: { model: \\\"glm-5.1\\\", provider: \\\"zai\\\" },\\n  escalation: { model: \\\"glm-5.1\\\", provider: \\\"zai\\\" },\\n  coordinator: { model: \\\"xiaomi/mimo-v2.5\\\", provider: \\\"openrouter\\\" },\\n};\\n\\nconst VALID_ROLES = [\\n  \\\"scout\\\", \\\"builder\\\", \\\"critic\\\", \\\"verifier\\\",\\n  \\\"integrator\\\", \\\"escalation\\\", \\\"coordinator\\\",\\n] as const;\\n\\n// ─── Persistence ─────────────────────────────────────────────────────\\n\\n/** Canonical Aedis state directory. Always used for writes. */\\nfunction configDir(projectRoot: string): string {\\n  return join(projectRoot, \\\".aedis\\\");\\n}\\n\\n/** Legacy Zendorium state directory, read-only fallback during the rename. */\\nfunction legacyConfigDir(projectRoot: string): string {\\n  return join(projectRoot, \\\".zendorium\\\");\\n}\\n\\nfunction configPath(projectRoot: string): string {\\n  return join(configDir(projectRoot), \\\"model-config.json\\\");\\n}\\n\\nfunction legacyConfigPath(projectRoot: string): string {\\n  return join(legacyConfigDir(projectRoot), \\\"model-config.json\\\");\\n}\\n\\nexport function loadModelConfig(projectRoot: string): ModelConfig {\\n  // Prefer the canonical .aedis/ path. Fall back to the legacy\\n  // .zendorium/ path so installs that were configured before the\\n  // rename still load their saved assignments. Writes always go to\\n  // the canonical path, so the legacy file stops being read the next\\n  // time the config is saved.\\n  const canonical = configPath(projectRoot);\\n  const legacy = legacyConfigPath(projectRoot);\\n  const pathsToTry = [canonical, legacy];\\n\\n  for (const path of pathsToTry) {\\n    try {\\n      if (existsSync(path)) {\\n        const raw = readFileSync(path, \\\"utf-8\\\");\\n        const parsed = JSON.parse(raw);\\n        // Merge with defaults so new roles get default values\\n        return { ...DEFAULT_MODEL_CONFIG, ...parsed };\\n      }\\n    } catch {\\n      // Corrupt file — try the next candidate, or fall through to defaults.\\n    }\\n  }\\n  return { ...DEFAULT_MODEL_CONFIG };\\n}\\n\\nfunction saveModelConfig(projectRoot: string, config: ModelConfig): void {\\n  const dir = configDir(projectRoot);\\n  if (!existsSync(dir)) {\\n    mkdirSync(dir, { recursive: true });\\n  }\\n  writeFileSync(configPath(projectRoot), JSON.stringify(config, null, 2) + \\\"\\\\n\\\", \\\"utf-8\\\");\\n}\\n\\nfunction validateModelConfig(body: unknown): { valid: boolean; errors: string[] } {\\n  const errors: string[] = [];\\n  if (typeof body !== \\\"object\\\" || body === null) {\\n    return { valid: false, errors: [\\\"Body must be a JSON object\\\"] };\\n  }\\n\\n  const obj = body as Record<string, unknown>;\\n\\n  for (const role of VALID_ROLES) {\\n    if (role in obj) {\\n      const entry = obj[role] as any;\\n      if (typeof entry !== \\\"object\\\" || entry === null) {\\n        errors.push(`${role} must be an object with { model, provider }`);\\n        continue;\\n      }\\n      if (typeof entry.model !== \\\"string\\\" || !entry.model.trim()) {\\n        errors.push(`${role}.model must be a non-empty string`);\\n      }\\n      if (typeof entry.provider !== \\\"string\\\" || !entry.provider.trim()) {\\n        errors.push(`${role}.provider must be a non-empty string`);\\n      }\\n    }\\n  }\\n\\n  // Warn about unknown keys but don't fail\\n  for (const key of Object.keys(obj)) {\\n    if (!VALID_ROLES.includes(key as any)) {\\n      errors.push(`Unknown role \\\"${key}\\\" — ignored`);\\n    }\\n  }\\n\\n  return { valid: errors.filter((e) => !e.includes(\\\"ignored\\\")).length === 0, errors };\\n}\\n\\n// ─── Routes ──────────────────────────────────────────────────────────\\n\\nexport const configRoutes: FastifyPluginAsync = async (fastify) => {\\n  const ctx = (): ServerContext => fastify.ctx;\\n\\n  /**\\n   * GET /config/models — Return current model assignments.\\n   */\\n  fastify.get(\\n    \\\"/models\\\",\\n    async (_request: FastifyRequest, reply: FastifyReply) => {\\n      const config = loadModelConfig(ctx().config.projectRoot);\\n      reply.send({\\n        models: config,\\n        config_path: configPath(ctx().config.projectRoot),\\n        roles: VALID_ROLES,\\n      });\\n    }\\n  );\\n\\n  /**\\n   * POST /config/models — Update model assignments.\\n   * Accepts a partial or full ModelConfig. Missing roles keep their current values.\\n   */\\n  fastify.post<{ Body: Partial<ModelConfig> | { models: Partial<ModelConfig> } }>(\\n    \\\"/models\\\",\\n    async (request, reply: FastifyReply) => {\\n      // Accept both shapes: the UI posts `{ models: {...} }`, early\\n      // CLI callers posted the flat ModelConfig directly. Unwrap once\\n      // here so downstream merge/validate logic only sees the role map.\\n      const raw = request.body as any;\\n      const assignments: Record<string, unknown> =\\n        raw && typeof raw === \\\"object\\\" && raw.models && typeof raw.models === \\\"object\\\"\\n          ? raw.models\\n          : (raw ?? {});\\n\\n      const { valid, errors } = validateModelConfig(assignments);\\n\\n      if (!valid) {\\n        reply.code(400).send({\\n          error: \\\"Validation failed\\\",\\n          errors,\\n        });\\n        return;\\n      }\\n\\n      const projectRoot = ctx().config.projectRoot;\\n      const current = loadModelConfig(projectRoot);\\n\\n      // Merge incoming assignments with current config\\n      const updated: ModelConfig = { ...current };\\n      for (const role of VALID_ROLES) {\\n        if (role in assignments) {\\n          (updated as any)[role] = (assignments as any)[role];\\n        }\\n      }\\n\\n      saveModelConfig(projectRoot, updated);\\n\\n      // Emit config change event\\n      ctx().eventBus.emit({\\n        type: \\\"config_event\\\",\\n        payload: {\\n          kind: \\\"config_update\\\",\\n          summary: \\\"Model configuration updated\\\",\\n          models: updated,\\n        },\\n      });\\n\\n      reply.send({\\n        models: updated,\\n        updated_roles: VALID_ROLES.filter((role) => role in assignments),\\n        message: \\\"Model configuration saved. Changes take effect on next run.\\\",\\n        warnings: errors.filter((e) => e.includes(\\\"ignored\\\")),\\n      });\\n    }\\n  );\\n};\\n\",\"lineCount\":241},{\"path\":\"server/routes/loqui.ts\",\"content\":\"/**\\n * Loqui route — Metrics + External API Layer v1.\\n *\\n * GET /loqui?question=&repoPath= — lightweight query-string\\n * variant of POST /tasks/loqui. Returns a grounded answer plus\\n * the list of repo files the gated context layer flagged as\\n * relevant to the question, and a rough confidence score so\\n * callers can tell \\\"I found context and got an answer\\\" apart\\n * from \\\"I had no relevant context.\\\"\\n *\\n * Design principles:\\n *\\n *   1. Read-only. No coordinator calls, no writes, no side\\n *      effects beyond what `askLoqui` already does (load memory,\\n *      gate context, call the model).\\n *   2. Grounded. Related files come from the same\\n *      project-memory + gated-context path the Coordinator uses\\n *      at plan time — so \\\"what does Loqui think is relevant\\\"\\n *      matches \\\"what Aedis would include in context if this were\\n *      a real run.\\\"\\n *   3. Thin handler. The underlying primitives are already\\n *      exported; this route composes them.\\n */\\n\\nimport { existsSync } from \\\"node:fs\\\";\\nimport type { FastifyPluginAsync, FastifyRequest, FastifyReply } from \\\"fastify\\\";\\nimport { answerLoqui } from \\\"../../core/loqui.js\\\";\\n\\ninterface LoquiQuery {\\n  question?: string;\\n  repoPath?: string;\\n}\\n\\nexport const loquiRoutes: FastifyPluginAsync = async (fastify) => {\\n  /**\\n   * GET /loqui?question=&repoPath=\\n   *\\n   * Response shape:\\n   *   {\\n   *     answer: string,\\n   *     confidence: number,        // 0..1\\n   *     relatedFiles: string[],\\n   *     reason: string,            // one-line explanation of the score\\n   *   }\\n   */\\n  fastify.get<{ Querystring: LoquiQuery }>(\\n    \\\"/\\\",\\n    async (\\n      request: FastifyRequest<{ Querystring: LoquiQuery }>,\\n      reply: FastifyReply,\\n    ) => {\\n      const question = String(request.query.question ?? \\\"\\\").trim();\\n      const repoPath = String(request.query.repoPath ?? \\\"\\\").trim();\\n\\n      if (!question) {\\n        reply.code(400).send({\\n          error: \\\"Bad request\\\",\\n          message: \\\"The `question` query parameter is required.\\\",\\n        });\\n        return;\\n      }\\n      if (!repoPath) {\\n        reply.code(400).send({\\n          error: \\\"Bad request\\\",\\n          message: \\\"The `repoPath` query parameter is required.\\\",\\n        });\\n        return;\\n      }\\n      if (!existsSync(repoPath)) {\\n        reply.code(400).send({\\n          error: \\\"Bad request\\\",\\n          message: `repoPath does not exist on this host: ${repoPath}`,\\n        });\\n        return;\\n      }\\n\\n      const result = await answerLoqui(question, repoPath);\\n\\n      reply.send({\\n        answer: result.answer,\\n        confidence: result.confidence,\\n        relatedFiles: result.relatedFiles,\\n        reason: result.reason,\\n        provider: result.provider,\\n      });\\n    },\\n  );\\n};\\n\",\"lineCount\":89},{\"path\":\"server/routes/metrics.ts\",\"content\":\"/**\\n * Metrics route — Metrics + External API Layer v1.\\n *\\n * GET /metrics — aggregate snapshot across every tracked run.\\n *\\n * Read-only. Delegates all aggregation to core/metrics.ts so the\\n * route handler stays thin and the pure function can be unit\\n * tested without Fastify.\\n */\\n\\nimport type { FastifyPluginAsync, FastifyReply, FastifyRequest } from \\\"fastify\\\";\\nimport { computeMetrics, type TrackedRunLike } from \\\"../../core/metrics.js\\\";\\nimport { getAllTrackedRuns } from \\\"./tasks.js\\\";\\n\\nexport const metricsRoutes: FastifyPluginAsync = async (fastify) => {\\n  /**\\n   * GET /metrics — Aggregate metrics across every tracked run.\\n   *\\n   * Reads from the tracked-run registry populated by POST /tasks\\n   * and POST /tasks/loqui/unified. Unfinished runs are counted\\n   * under `inFlightRuns`; only terminal runs contribute to\\n   * `successRate`. Cost / file / confidence averages exclude\\n   * unfinished runs so an idle queue does not dilute the numbers.\\n   */\\n  fastify.get(\\n    \\\"/\\\",\\n    async (_request: FastifyRequest, reply: FastifyReply) => {\\n      const tracked = getAllTrackedRuns() as unknown as readonly TrackedRunLike[];\\n      const persistedIndex = await fastify.ctx.receiptStore.listRuns(1000);\\n      const persistedRuns = await Promise.all(\\n        persistedIndex.map(async (entry): Promise<TrackedRunLike | null> => {\\n          const persisted = await fastify.ctx.receiptStore.getRun(entry.runId);\\n          if (!persisted) return null;\\n          const task = await fastify.ctx.receiptStore.getTaskByRunId(entry.runId);\\n          return {\\n            taskId: task?.taskId ?? persisted.runId,\\n            runId: persisted.runId,\\n            status:\\n              persisted.status === \\\"RUNNING\\\" || persisted.status === \\\"EXECUTING_IN_WORKSPACE\\\" || persisted.status === \\\"PROPOSED\\\" || persisted.status === \\\"VERIFICATION_PENDING\\\"\\n                ? \\\"running\\\"\\n                : persisted.status === \\\"COMPLETE\\\" || persisted.status === \\\"VERIFIED_PASS\\\" || persisted.status === \\\"READY_FOR_PROMOTION\\\"\\n                  ? \\\"complete\\\"\\n                  : persisted.status === \\\"ABORTED\\\" || persisted.status === \\\"INTERRUPTED\\\"\\n                    ? \\\"cancelled\\\"\\n                    : \\\"failed\\\",\\n            prompt: task?.prompt ?? persisted.prompt,\\n            submittedAt: task?.submittedAt ?? persisted.startedAt ?? persisted.createdAt,\\n            completedAt: persisted.completedAt,\\n            receipt: persisted.finalReceipt,\\n            error: persisted.errors[0] ?? task?.error ?? null,\\n            stateCategory:\\n              persisted.status === \\\"RUNNING\\\" || persisted.status === \\\"EXECUTING_IN_WORKSPACE\\\" || persisted.status === \\\"PROPOSED\\\" || persisted.status === \\\"VERIFICATION_PENDING\\\"\\n                ? \\\"in-flight\\\"\\n                : persisted.status === \\\"CRASHED\\\" || persisted.status === \\\"EXECUTION_ERROR\\\" || persisted.status === \\\"CLEANUP_ERROR\\\"\\n                  ? \\\"crashed\\\"\\n                  : persisted.status === \\\"COMPLETE\\\" || persisted.status === \\\"VERIFIED_PASS\\\" || persisted.status === \\\"READY_FOR_PROMOTION\\\"\\n                    ? \\\"completed\\\"\\n                    : persisted.status === \\\"DISAGREEMENT_HOLD\\\"\\n                      ? \\\"blocked\\\"\\n                      : \\\"failed\\\",\\n          };\\n        }),\\n      );\\n\\n      const byRunId = new Map<string, TrackedRunLike>();\\n      for (const run of persistedRuns) {\\n        if (!run?.runId) continue;\\n        byRunId.set(run.runId, run);\\n      }\\n      for (const run of tracked) {\\n        if (!run.runId) continue;\\n        byRunId.set(run.runId, run);\\n      }\\n\\n      const snapshot = computeMetrics([...byRunId.values()]);\\n      reply.send(snapshot);\\n    }\\n  );\\n};\\n\",\"lineCount\":80},{\"path\":\"server/index.ts\",\"content\":\"/**\\n * Aedis Server — Fastify + WebSocket on port 18796.\\n *\\n * Entry point for the Aedis API. Mounts all route files,\\n * connects to the Coordinator, and streams events over WebSocket.\\n * Serves ui/ as static files at / and /ui/*.\\n *\\n * Can be run directly: node server/index.js\\n */\\n\\nimport \\\"dotenv/config\\\";\\n\\nimport { existsSync, readFileSync } from \\\"fs\\\";\\nimport { fileURLToPath } from \\\"url\\\";\\nimport { dirname, join } from \\\"path\\\";\\nimport Fastify from \\\"fastify\\\";\\nimport websocket from \\\"@fastify/websocket\\\";\\nimport fastifyStatic from \\\"@fastify/static\\\";\\nimport cors from \\\"@fastify/cors\\\";\\n\\nimport { createTailscaleAuth } from \\\"./middleware/auth.js\\\";\\nimport { createEventBus, type EventBus } from \\\"./websocket.js\\\";\\nimport { Coordinator, type CoordinatorConfig } from \\\"../core/coordinator.js\\\";\\nimport { ReceiptStore } from \\\"../core/receipt-store.js\\\";\\nimport {\\n  createCustomHook,\\n  createTypecheckHook,\\n  type ToolHook,\\n  type VerificationPipelineConfig,\\n} from \\\"../core/verification-pipeline.js\\\";\\nimport { WorkerRegistry } from \\\"../workers/base.js\\\";\\nimport { ScoutWorker } from \\\"../workers/scout.js\\\";\\nimport { BuilderWorker } from \\\"../workers/builder.js\\\";\\nimport { CriticWorker } from \\\"../workers/critic.js\\\";\\nimport { VerifierWorker } from \\\"../workers/verifier.js\\\";\\nimport { IntegratorWorker } from \\\"../workers/integrator.js\\\";\\nimport type { TrustProfile } from \\\"../router/trust-router.js\\\";\\n\\nimport { costRoutes } from \\\"./routes/cost.js\\\";\\nimport { taskRoutes } from \\\"./routes/tasks.js\\\";\\nimport { runRoutes } from \\\"./routes/runs.js\\\";\\nimport { workerRoutes } from \\\"./routes/workers.js\\\";\\nimport { healthRoutes } from \\\"./routes/health.js\\\";\\nimport { configRoutes } from \\\"./routes/config.js\\\";\\nimport { providerRoutes } from \\\"./routes/providers.js\\\";\\nimport { metricsRoutes } from \\\"./routes/metrics.js\\\";\\nimport { loquiRoutes } from \\\"./routes/loqui.js\\\";\\nimport { trustRoutes } from \\\"./routes/trust.js\\\";\\nimport { proveRoutes } from \\\"./routes/prove.js\\\";\\nimport { reliabilityRoutes } from \\\"./routes/reliability.js\\\";\\nimport { campaignRoutes } from \\\"./routes/campaign.js\\\";\\nimport { sessionRoutes } from \\\"./routes/sessions.js\\\";\\nimport { memoryRoutes } from \\\"./routes/memory.js\\\";\\n\\n// ─── Types ───────────────────────────────────────────────────────────\\n\\nexport interface ServerConfig {\\n  port: number;\\n  host: string;\\n  projectRoot: string;\\n  coordinatorConfig?: Partial<CoordinatorConfig>;\\n  /** Disable Tailscale auth (for local dev) */\\n  disableAuth?: boolean;\\n  /** Additional allowed CIDRs */\\n  allowedCidrs?: string[];\\n}\\n\\nconst DEFAULT_CONFIG: ServerConfig = {\\n  port: 18796,\\n  host: \\\"0.0.0.0\\\",\\n  projectRoot: process.cwd(),\\n};\\n\\n// ─── Server Context (shared across routes) ───────────────────────────\\n\\nexport interface ServerContext {\\n  coordinator: Coordinator;\\n  eventBus: EventBus;\\n  receiptStore: ReceiptStore;\\n  workerRegistry: WorkerRegistry;\\n  config: ServerConfig;\\n  startedAt: string;\\n}\\n\\n// ─── Defaults for standalone boot ────────────────────────────────────\\n\\nfunction defaultTrustProfile(): TrustProfile {\\n  return {\\n    scores: new Map(),\\n    tierThresholds: { fast: 0.6, standard: 0.75, premium: 0.9 },\\n  };\\n}\\n\\n/**\\n * Build a WorkerRegistry with all 5 worker types registered.\\n */\\n/**\\n * Detect the primary language/stack of a project so the verifier can\\n * pick the right hooks. Returns an ordered list of detected stacks —\\n * a repo with both package.json AND pyproject.toml (rare but real)\\n * gets both. Godot projects are detected via project.godot.\\n */\\nfunction detectProjectStacks(projectRoot: string): ReadonlyArray<\\\"typescript\\\" | \\\"python\\\" | \\\"godot\\\" | \\\"rust\\\" | \\\"go\\\" | \\\"unknown\\\"> {\\n  const stacks: Array<\\\"typescript\\\" | \\\"python\\\" | \\\"godot\\\" | \\\"rust\\\" | \\\"go\\\" | \\\"unknown\\\"> = [];\\n  if (existsSync(join(projectRoot, \\\"tsconfig.json\\\")) || existsSync(join(projectRoot, \\\"package.json\\\"))) {\\n    stacks.push(\\\"typescript\\\");\\n  }\\n  if (\\n    existsSync(join(projectRoot, \\\"pyproject.toml\\\")) ||\\n    existsSync(join(projectRoot, \\\"requirements.txt\\\")) ||\\n    existsSync(join(projectRoot, \\\"setup.py\\\")) ||\\n    existsSync(join(projectRoot, \\\"Pipfile\\\"))\\n  ) {\\n    stacks.push(\\\"python\\\");\\n  }\\n  if (existsSync(join(projectRoot, \\\"project.godot\\\"))) stacks.push(\\\"godot\\\");\\n  if (existsSync(join(projectRoot, \\\"Cargo.toml\\\"))) stacks.push(\\\"rust\\\");\\n  if (existsSync(join(projectRoot, \\\"go.mod\\\"))) stacks.push(\\\"go\\\");\\n  if (stacks.length === 0) stacks.push(\\\"unknown\\\");\\n  return stacks;\\n}\\n\\nfunction buildVerificationConfig(projectRoot: string): Partial<VerificationPipelineConfig> {\\n  const hooks: ToolHook[] = [];\\n  let scripts: Record<string, string> = {};\\n  const stacks = detectProjectStacks(projectRoot);\\n  console.log(`[server] project stacks detected at ${projectRoot}: ${stacks.join(\\\", \\\")}`);\\n\\n  const packageJsonPath = join(projectRoot, \\\"package.json\\\");\\n  if (existsSync(packageJsonPath)) {\\n    try {\\n      const packageJson = JSON.parse(readFileSync(packageJsonPath, \\\"utf-8\\\")) as {\\n        scripts?: Record<string, string>;\\n      };\\n      scripts = packageJson.scripts ?? {};\\n    } catch {\\n      scripts = {};\\n    }\\n  }\\n\\n  if (typeof scripts.lint === \\\"string\\\" && scripts.lint.trim()) {\\n    hooks.push(createCustomHook({\\n      name: \\\"Lint\\\",\\n      command: \\\"npm\\\",\\n      args: [\\\"run\\\", \\\"lint\\\"],\\n      kind: \\\"lint\\\",\\n    }));\\n  }\\n\\n  const tsconfigPath = join(projectRoot, \\\"tsconfig.json\\\");\\n  if (existsSync(tsconfigPath)) {\\n    hooks.push(createTypecheckHook({ project: tsconfigPath }));\\n  }\\n\\n  if (typeof scripts.test === \\\"string\\\" && scripts.test.trim()) {\\n    hooks.push(createCustomHook({\\n      name: \\\"Tests\\\",\\n      command: \\\"npm\\\",\\n      args: [\\\"run\\\", \\\"test\\\"],\\n      kind: \\\"tests\\\",\\n    }));\\n  }\\n\\n  // Language-agnostic hooks. The verifier runs every registered hook\\n  // against the ACTIVE workspace at dispatch time (cwd is per-run, not\\n  // per-boot). We can't know at boot whether a given run will target a\\n  // Python repo or a Godot repo — so we register the hooks\\n  // unconditionally, guarded by their own \\\"are there files to check?\\\"\\n  // logic, and let them no-op on repos that don't match.\\n  //\\n  // Python: syntax-check every .py file with python3 -m py_compile. On\\n  // a TS repo with no .py files, `xargs -r` makes the command a no-op\\n  // and exits 0. On a Python repo it catches import typos / unmatched\\n  // parens / unterminated strings. Only registered if python3 is on\\n  // PATH.\\n  if (hasExecutableOnPath(\\\"python3\\\")) {\\n    hooks.push(createCustomHook({\\n      name: \\\"Python Syntax\\\",\\n      command: \\\"sh\\\",\\n      args: [\\\"-c\\\", \\\"find . -type f -name '*.py' -not -path './.venv/*' -not -path './venv/*' -not -path './__pycache__/*' -not -path './node_modules/*' -not -path './.git/*' 2>/dev/null | head -500 | xargs -r python3 -m py_compile\\\"],\\n      kind: \\\"typecheck\\\",\\n    }));\\n  }\\n\\n  // Godot: headless --check-only validates scripts + scenes. The\\n  // `--check-only` flag exits 0 on success, nonzero if any script\\n  // fails to parse. Only registered if the godot binary is on PATH\\n  // AND this run's cwd has a project.godot — the sh wrapper short-\\n  // circuits on non-Godot repos.\\n  if (hasExecutableOnPath(\\\"godot\\\")) {\\n    hooks.push(createCustomHook({\\n      name: \\\"Godot Check\\\",\\n      command: \\\"sh\\\",\\n      args: [\\\"-c\\\", \\\"[ -f project.godot ] || exit 0; godot --headless --quit --check-only\\\"],\\n      kind: \\\"typecheck\\\",\\n    }));\\n  }\\n\\n  // Required checks: whichever typecheck-class hooks we managed to\\n  // register. An empty list means the verifier won't fail closed on\\n  // \\\"missing required checks\\\" — for an unknown-stack repo, the diff /\\n  // contract / cross-file stages still run and still gate.\\n  const requiredChecks = hooks.some((h) => h.kind === \\\"typecheck\\\")\\n    ? [\\\"typecheck\\\"] as const\\n    : [] as const;\\n\\n  return {\\n    hooks,\\n    requiredChecks: [...requiredChecks],\\n    strictMode: process.env[\\\"AEDIS_STRICT_MODE\\\"] === \\\"true\\\",\\n  };\\n}\\n\\n/**\\n * Cheap which(1): returns true if the command resolves on PATH. Used\\n * so we don't register hooks that would blow up with ENOENT.\\n */\\nfunction hasExecutableOnPath(cmd: string): boolean {\\n  try {\\n    const paths = (process.env[\\\"PATH\\\"] ?? \\\"\\\").split(\\\":\\\").filter(Boolean);\\n    for (const p of paths) {\\n      if (existsSync(join(p, cmd))) return true;\\n    }\\n    return false;\\n  } catch {\\n    return false;\\n  }\\n}\\n\\nfunction buildDefaultRegistry(projectRoot: string, verificationConfig: Partial<VerificationPipelineConfig>): WorkerRegistry {\\n  const registry = new WorkerRegistry();\\n  registry.register(new ScoutWorker({ projectRoot }));\\n  registry.register(new BuilderWorker({ projectRoot }));\\n  registry.register(new CriticWorker({ projectRoot }));\\n  registry.register(new VerifierWorker({\\n    hooks: verificationConfig.hooks ?? [],\\n    verificationConfig,\\n  }));\\n  registry.register(new IntegratorWorker());\\n  console.log(\\\"[server] WorkerRegistry: 5 workers registered — scout, builder, critic, verifier, integrator\\\");\\n  return registry;\\n}\\n\\n// ─── Resolve ui/ directory relative to this file ─────────────────────\\n\\nconst __filename = fileURLToPath(import.meta.url);\\nconst __dirname = dirname(__filename);\\n\\nfunction resolveUiRoot(): string {\\n  const siblingUi = join(__dirname, \\\"..\\\", \\\"ui\\\");\\n  if (existsSync(siblingUi)) return siblingUi;\\n\\n  // Built output lives in dist/server, while source ui/ stays at repo-root/ui.\\n  const repoUi = join(__dirname, \\\"..\\\", \\\"..\\\", \\\"ui\\\");\\n  if (existsSync(repoUi)) return repoUi;\\n\\n  return siblingUi;\\n}\\n\\nconst UI_ROOT = resolveUiRoot();\\n\\n// ─── Boot ────────────────────────────────────────────────────────────\\n\\nexport async function createServer(\\n  config: Partial<ServerConfig> = {},\\n  trustProfile?: TrustProfile,\\n  workerRegistry?: WorkerRegistry\\n): Promise<ReturnType<typeof Fastify>> {\\n  const cfg: ServerConfig = { ...DEFAULT_CONFIG, ...config };\\n  const verificationConfig = buildVerificationConfig(cfg.projectRoot);\\n  const registry = workerRegistry ?? buildDefaultRegistry(cfg.projectRoot, verificationConfig);\\n  const profile = trustProfile ?? defaultTrustProfile();\\n\\n  const eventBus = createEventBus();\\n  const receiptStore = new ReceiptStore(cfg.projectRoot);\\n  const recovery = await receiptStore.markIncompleteRunsCrashed(\\n    `Server restarted on ${new Date().toISOString()} before the run reached a terminal state`,\\n  );\\n  if (recovery.runsRecovered > 0) {\\n    console.log(\\n      `[server] STARTUP RECOVERY: ${recovery.runsRecovered} run(s) marked INTERRUPTED; ` +\\n      `orphan workspaces=${recovery.orphanWorkspaces.length} ` +\\n      `(removed=${recovery.orphanWorkspaces.filter((o) => o.removed).length})`,\\n    );\\n    for (const orphan of recovery.orphanWorkspaces) {\\n      console.log(\\n        `[server] STARTUP RECOVERY: workspace ${orphan.workspacePath} — ` +\\n        (orphan.removed ? \\\"cleaned\\\" : `FAILED: ${orphan.error ?? \\\"unknown\\\"}`),\\n      );\\n    }\\n  }\\n\\n  // Auto-promote is opt-in via env (AEDIS_AUTO_PROMOTE=true). When set,\\n  // a run that finishes with a clean VERIFIED_SUCCESS classification\\n  // has its workspace commit automatically applied to the source repo\\n  // as a real commit. Without it, runs land in the workspace only and\\n  // require an explicit POST /tasks/:id/promote.\\n  const autoPromoteOnSuccess = process.env[\\\"AEDIS_AUTO_PROMOTE\\\"] === \\\"true\\\";\\n  if (autoPromoteOnSuccess) {\\n    console.log(\\\"[server] AEDIS_AUTO_PROMOTE=true — clean runs will auto-promote to source repo\\\");\\n  }\\n\\n  const coordinator = new Coordinator(\\n    {\\n      projectRoot: cfg.projectRoot,\\n      verificationConfig,\\n      autoPromoteOnSuccess,\\n      ...cfg.coordinatorConfig,\\n    },\\n    profile,\\n    registry,\\n    eventBus,\\n    receiptStore,\\n  );\\n\\n  const ctx: ServerContext = {\\n    coordinator,\\n    eventBus,\\n    receiptStore,\\n    workerRegistry: registry,\\n    config: cfg,\\n    startedAt: new Date().toISOString(),\\n  };\\n\\n  // ─── Fastify instance ──────────────────────────────────────────\\n\\n  const server = Fastify({\\n    logger: {\\n      level: \\\"info\\\",\\n    },\\n  });\\n\\n  // ─── Plugins ───────────────────────────────────────────────────\\n\\n  await server.register(cors, {\\n    origin: true,\\n    methods: [\\\"GET\\\", \\\"POST\\\", \\\"DELETE\\\", \\\"OPTIONS\\\"],\\n  });\\n\\n  await server.register(websocket);\\n\\n  // ─── Static files: ui/ at /ui/* ────────────────────────────────\\n\\n  await server.register(fastifyStatic, {\\n    root: UI_ROOT,\\n    prefix: \\\"/ui/\\\",\\n  });\\n\\n  // ─── GET / → serve ui/index.html directly ─────────────────────\\n\\n  const indexHtmlPath = join(UI_ROOT, \\\"index.html\\\");\\n  let indexHtml: string;\\n  try {\\n    indexHtml = readFileSync(indexHtmlPath, \\\"utf-8\\\");\\n  } catch {\\n    indexHtml = \\\"<html><body><h1>Aedis</h1><p>ui/index.html not found</p></body></html>\\\";\\n  }\\n\\n  server.get(\\\"/\\\", async (_request, reply) => {\\n    reply.type(\\\"text/html\\\").send(indexHtml);\\n  });\\n\\n  // ─── Auth middleware ───────────────────────────────────────────\\n\\n  server.addHook(\\n    \\\"onRequest\\\",\\n    createTailscaleAuth({\\n      enabled: !cfg.disableAuth,\\n      allowedCidrs: cfg.allowedCidrs ?? [],\\n    })\\n  );\\n\\n  // ─── Decorate with context ────────────────────────────────────\\n\\n  server.decorate(\\\"ctx\\\", ctx);\\n\\n  // ─── Routes ────────────────────────────────────────────────────\\n\\n  await server.register(taskRoutes, { prefix: \\\"/tasks\\\" });\\n  await server.register(runRoutes, { prefix: \\\"/runs\\\" });\\n  await server.register(workerRoutes, { prefix: \\\"/workers\\\" });\\n  // External API layer — /api/* mirrors the internal routes for external consumers\\n  // (Crucibulum, CLI tools) that expect the /api prefix convention.\\n  await server.regist