erver.register(async function (fastify) {\\n    fastify.get(\\\"/ws\\\", { websocket: true }, (socket /* WebSocket */, req) => {\\n\\n      // Parse optional event filter from query\\n      const url = new URL(req.url ?? \\\"/\\\", `http://${req.headers.host ?? \\\"localhost\\\"}`);\\n      const filterParam = url.searchParams.get(\\\"events\\\");\\n      const filter = filterParam\\n        ? (filterParam.split(\\\",\\\") as any[])\\n        : undefined;\\n\\n      eventBus.addClient(socket as any, filter);\\n\\n      // Send welcome message\\n      try {\\n        socket.send(JSON.stringify({\\n          type: \\\"connected\\\",\\n          timestamp: new Date().toISOString(),\\n          message: \\\"Aedis WebSocket connected\\\",\\n          clients: eventBus.clientCount(),\\n        }));\\n      } catch {\\n        // Socket may have closed\\n      }\\n\\n      // Keepalive ping every 30s\\n      const keepalive = setInterval(() => {\\n        try {\\n          if (socket.readyState === 1) {\\n            socket.ping();\\n          } else {\\n            clearInterval(keepalive);\\n          }\\n        } catch {\\n          clearInterval(keepalive);\\n        }\\n      }, 30_000);\\n\\n      socket.on(\\\"close\\\", () => {\\n        clearInterval(keepalive);\\n        eventBus.removeClient(socket as any);\\n      });\\n\\n      socket.on(\\\"error\\\", () => {\\n        clearInterval(keepalive);\\n        eventBus.removeClient(socket as any);\\n      });\\n\\n      // Handle client messages\\n      socket.on(\\\"message\\\", (data: Buffer) => {\\n        try {\\n          const msg = JSON.parse(data.toString());\\n          if (msg.type === \\\"ping\\\") {\\n            socket.send(JSON.stringify({ type: \\\"pong\\\", timestamp: new Date().toISOString() }));\\n          }\\n          if (msg.type === \\\"subscribe\\\") {\\n            socket.send(JSON.stringify({\\n              type: \\\"subscribed\\\",\\n              taskId: msg.taskId,\\n              runId: msg.runId,\\n              timestamp: new Date().toISOString(),\\n            }));\\n          }\\n        } catch {\\n          // Ignore malformed messages\\n        }\\n      });\\n    });\\n  });\\n\\n  return server;\\n}\\n\\n// ─── Standalone boot ─────────────────────────────────────────────────\\n\\nexport async function startServer(\\n  config: Partial<ServerConfig> = {},\\n  trustProfile?: TrustProfile,\\n  workerRegistry?: WorkerRegistry\\n): Promise<void> {\\n  const cfg = { ...DEFAULT_CONFIG, ...config };\\n  const server = await createServer(cfg, trustProfile, workerRegistry);\\n\\n  try {\\n    const address = await server.listen({ port: cfg.port, host: cfg.host });\\n    server.log.info(`Aedis server listening on ${address}`);\\n    server.log.info(`WebSocket available at ws://${cfg.host}:${cfg.port}/ws`);\\n    server.log.info(`UI available at http://${cfg.host}:${cfg.port}/`);\\n  } catch (err) {\\n    server.log.error(err);\\n    process.exit(1);\\n  }\\n\\n  // Graceful shutdown\\n  const shutdown = async () => {\\n    server.log.info(\\\"Shutting down Aedis server...\\\");\\n    await server.close();\\n    process.exit(0);\\n  };\\n\\n  process.on(\\\"SIGINT\\\", shutdown);\\n  process.on(\\\"SIGTERM\\\", shutdown);\\n}\\n\\n// ─── Self-boot when run directly ─────────────────────────────────────\\n\\nconst isDirectRun =\\n  process.argv[1]?.endsWith(\\\"server/index.js\\\") ||\\n  process.argv[1]?.endsWith(\\\"server/index.ts\\\");\\n\\nif (isDirectRun) {\\n  startServer().catch((err) => {\\n    console.error(\\\"Aedis server failed to start:\\\", err);\\n    process.exit(1);\\n  });\\n}\\n\\n// ─── Type augmentation for Fastify ───────────────────────────────────\\n\\ndeclare module \\\"fastify\\\" {\\n  interface FastifyInstance {\\n    ctx: ServerContext;\\n  }\\n}\\n\",\"lineCount\":545},{\"path\":\"server/middleware/auth.ts\",\"content\":\"/**\\n * Tailscale auth middleware — Aedis access control.\\n *\\n * Only accepts connections from Tailscale IP range (100.x.x.x).\\n * All rejected attempts are logged with source IP and timestamp.\\n */\\n\\nimport type { FastifyRequest, FastifyReply, HookHandlerDoneFunction } from \\\"fastify\\\";\\n\\n// ─── Types ───────────────────────────────────────────────────────────\\n\\nexport interface AuthConfig {\\n  /** Enable or disable auth (disable for local dev) */\\n  enabled: boolean;\\n  /** Additional allowed CIDRs beyond Tailscale */\\n  allowedCidrs: string[];\\n  /** Log rejected attempts */\\n  logRejections: boolean;\\n}\\n\\nconst DEFAULT_CONFIG: AuthConfig = {\\n  enabled: true,\\n  allowedCidrs: [],\\n  logRejections: true,\\n};\\n\\n// ─── Tailscale IP Check ──────────────────────────────────────────────\\n\\nconst TAILSCALE_PREFIX = \\\"100.\\\";\\n\\nfunction isTailscaleIp(ip: string): boolean {\\n  // Tailscale CGNAT range: 100.64.0.0/10 (100.64.x.x - 100.127.x.x)\\n  // In practice, Tailscale assigns from the full 100.x.x.x range\\n  if (!ip.startsWith(TAILSCALE_PREFIX)) return false;\\n\\n  const parts = ip.split(\\\".\\\");\\n  if (parts.length !== 4) return false;\\n\\n  return parts.every((p) => {\\n    const n = parseInt(p, 10);\\n    return !isNaN(n) && n >= 0 && n <= 255;\\n  });\\n}\\n\\nfunction isLoopback(ip: string): boolean {\\n  return ip === \\\"127.0.0.1\\\" || ip === \\\"::1\\\" || ip === \\\"::ffff:127.0.0.1\\\";\\n}\\n\\nfunction matchesCidr(ip: string, cidr: string): boolean {\\n  const [network, prefixStr] = cidr.split(\\\"/\\\");\\n  if (!network || !prefixStr) return ip === cidr;\\n\\n  const prefix = parseInt(prefixStr, 10);\\n  if (isNaN(prefix)) return false;\\n\\n  const ipNum = ipToNumber(ip);\\n  const netNum = ipToNumber(network);\\n  if (ipNum === null || netNum === null) return false;\\n\\n  const mask = ~((1 << (32 - prefix)) - 1) >>> 0;\\n  return (ipNum & mask) === (netNum & mask);\\n}\\n\\nfunction ipToNumber(ip: string): number | null {\\n  // Strip IPv6 prefix\\n  const clean = ip.replace(/^::ffff:/, \\\"\\\");\\n  const parts = clean.split(\\\".\\\");\\n  if (parts.length !== 4) return null;\\n\\n  let num = 0;\\n  for (const part of parts) {\\n    const n = parseInt(part, 10);\\n    if (isNaN(n) || n < 0 || n > 255) return null;\\n    num = (num << 8) | n;\\n  }\\n  return num >>> 0;\\n}\\n\\n// ─── Extract Client IP ──────────────────────────────────────────────\\n\\nfunction getClientIp(request: FastifyRequest): string {\\n  // Check X-Forwarded-For first (reverse proxy)\\n  const forwarded = request.headers[\\\"x-forwarded-for\\\"];\\n  if (forwarded) {\\n    const first = Array.isArray(forwarded) ? forwarded[0] : forwarded.split(\\\",\\\")[0];\\n    return first.trim();\\n  }\\n\\n  // Check X-Real-IP\\n  const realIp = request.headers[\\\"x-real-ip\\\"];\\n  if (realIp) {\\n    return Array.isArray(realIp) ? realIp[0] : realIp;\\n  }\\n\\n  // Fall back to socket address\\n  return request.ip;\\n}\\n\\n// ─── Middleware Factory ──────────────────────────────────────────────\\n\\nexport function createTailscaleAuth(config: Partial<AuthConfig> = {}) {\\n  const cfg: AuthConfig = { ...DEFAULT_CONFIG, ...config };\\n\\n  return function tailscaleAuth(\\n    request: FastifyRequest,\\n    reply: FastifyReply,\\n    done: HookHandlerDoneFunction\\n  ): void {\\n    if (!cfg.enabled) {\\n      done();\\n      return;\\n    }\\n\\n    const clientIp = getClientIp(request);\\n\\n    // Allow loopback\\n    if (isLoopback(clientIp)) {\\n      done();\\n      return;\\n    }\\n\\n    // Allow Tailscale IPs\\n    if (isTailscaleIp(clientIp)) {\\n      done();\\n      return;\\n    }\\n\\n    // Check additional allowed CIDRs\\n    for (const cidr of cfg.allowedCidrs) {\\n      if (matchesCidr(clientIp, cidr)) {\\n        done();\\n        return;\\n      }\\n    }\\n\\n    // Rejected\\n    if (cfg.logRejections) {\\n      const log = request.log ?? console;\\n      log.warn({\\n        msg: \\\"Rejected non-Tailscale connection\\\",\\n        ip: clientIp,\\n        method: request.method,\\n        url: request.url,\\n        timestamp: new Date().toISOString(),\\n      });\\n    }\\n\\n    reply\\n      .code(403)\\n      .header(\\\"Content-Type\\\", \\\"application/json\\\")\\n      .send({\\n        error: \\\"Forbidden\\\",\\n        message: \\\"Access restricted to Tailscale network\\\",\\n      });\\n  };\\n}\\n\",\"lineCount\":157}],\"summaries\":[{\"imports\":[\"fastify\",\"../index.js\",\"../../workers/base.js\"],\"exports\":[\"healthRoutes\"],\"functions\":[\"ctx\",\"formatUptime\"],\"classes\":[],\"patterns\":[\"imports\",\"exports\"],\"summary\":\"3 imports; 1 exports; 2 functions; patterns imports, exports\"},{\"imports\":[\"crypto\",\"fs\",\"fastify\",\"../../core/loqui.js\",\"../../core/loqui-router.js\",\"../../core/loqui-intent.js\",\"../../core/dry-run.js\",\"../index.js\"],\"exports\":[\"getTrackedRun\",\"getAllTrackedRuns\",\"taskRoutes\"],\"functions\":[\"getTrackedRun\",\"getAllTrackedRuns\",\"submitBuildTask\",\"findLatestTrackedRun\",\"findLatestKnownRun\",\"findKnownRunById\",\"ctx\",\"cancelTrackedTask\",\"toTaskStatus\",\"runId\"],\"classes\":[],\"patterns\":[\"imports\",\"exports\",\"test-file\"],\"summary\":\"8 imports; 3 exports; 10 functions; patterns imports, exports, test-file\"},{\"imports\":[\"fs\",\"path\",\"fastify\",\"../index.js\"],\"exports\":[\"ModelAssignment\",\"ModelConfig\",\"loadModelConfig\",\"configRoutes\"],\"functions\":[\"configDir\",\"legacyConfigDir\",\"configPath\",\"legacyConfigPath\",\"loadModelConfig\",\"saveModelConfig\",\"validateModelConfig\",\"ctx\"],\"classes\":[],\"patterns\":[\"imports\",\"exports\",\"test-file\"],\"summary\":\"4 imports; 4 exports; 8 functions; patterns imports, exports, test-file\"},{\"imports\":[\"node:fs\",\"fastify\",\"../../core/loqui.js\"],\"exports\":[\"loquiRoutes\"],\"functions\":[],\"classes\":[],\"patterns\":[\"imports\",\"exports\"],\"summary\":\"3 imports; 1 exports; patterns imports, exports\"},{\"imports\":[\"fastify\",\"../../core/